// SecureLocalDataManager.js
// A comprehensive React Native local data manager with proper security practices

import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';

// ============================================================
// STORAGE KEY CONSTANTS
// ============================================================

const KEYS = {
  // Non-sensitive keys (AsyncStorage)
  APP_SETTINGS: '@app_settings',
  USER_PROFILE_PUBLIC: '@user_profile_public',
  UI_PREFERENCES: '@ui_preferences',
  OFFLINE_CONTENT: '@offline_content',
  CACHE_METADATA: '@cache_metadata',
  SESSION_UI_STATE: '@session_ui_state',
  ONBOARDING_COMPLETED: '@onboarding_completed',
  LAST_SYNC_TIMESTAMP: '@last_sync_timestamp',
  CACHED_FEED: '@cached_feed',
  NOTIFICATION_PREFERENCES: '@notification_preferences',

  // Sensitive keys (SecureStore / Keychain)
  SECURE_AUTH_TOKEN: 'secure_auth_token',
  SECURE_REFRESH_TOKEN: 'secure_refresh_token',
  SECURE_USER_ID: 'secure_user_id',
  SECURE_SESSION_ID: 'secure_session_id',
  SECURE_API_KEY: 'secure_api_key',
  SECURE_BIOMETRIC_FLAG: 'secure_biometric_enabled',
};

// ============================================================
// SECURE STORAGE WRAPPER (Keychain/Keystore backed)
