class SecureStorageManager {
  /**
   * Store a sensitive value in the platform's secure enclave.
   * NEVER store tokens, passwords, or secrets in AsyncStorage.
   */
  static async setSecureItem(key, value) {
    if (value === null || value === undefined) {
      await SecureStore.deleteItemAsync(key);
      return;
    }
    const stringValue = typeof value === 'string' ? value : JSON.stringify(value);
    await SecureStore.setItemAsync(key, stringValue, {
      keychainAccessible: SecureStore.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
    });
  }

  static async getSecureItem(key) {
    const value = await SecureStore.getItemAsync(key);
    if (value === null) return null;
    try {
      return JSON.parse(value);
    } catch {
      return value;
    }
  }

  static async removeSecureItem(key) {
    await SecureStore.deleteItemAsync(key);
  }

  static async clearAllSecureItems() {
    const secureKeys = [
      KEYS.SECURE_AUTH_TOKEN,
      KEYS.SECURE_REFRESH_TOKEN,
      KEYS.SECURE_USER_ID,
      KEYS.SECURE_SESSION_ID,
      KEYS.SECURE_API_KEY,
      KEYS.SECURE_BIOMETRIC_FLAG,
    ];
    await Promise.all(secureKeys.map((key) => SecureStore.deleteItemAsync(key)));
  }
}

