class CacheStorageManager {
  /**
   * Store a non-sensitive value in AsyncStorage for fast UI access.
   * This must NEVER contain tokens, passwords, or authentication secrets.
   */
  static async setItem(key, value, ttlMinutes = null) {
    const wrapper = {
      data: value,
      timestamp: Date.now(),
      expiresAt: ttlMinutes ? Date.now() + ttlMinutes * 60 * 1000 : null,
    };
    await AsyncStorage.setItem(key, JSON.stringify(wrapper));
  }

  static async getItem(key) {
    const raw = await AsyncStorage.getItem(key);
    if (raw === null) return null;

    try {
      const wrapper = JSON.parse(raw);

      // Check TTL expiration
      if (wrapper.expiresAt && Date.now() > wrapper.expiresAt) {
        await AsyncStorage.removeItem(key);
        return null;
      }

      return wrapper.data;
    } catch {
      // If parsing fails, remove corrupted data
      await AsyncStorage.removeItem(key);
      return null;
    }
  }

  static async removeItem(key) {
    await AsyncStorage.removeItem(key);
  }

  static async getItemWithMetadata(key) {
    const raw = await AsyncStorage.getItem(key);
    if (raw === null) return null;

    try {
      const wrapper = JSON.parse(raw);
      if (wrapper.expiresAt && Date.now() > wrapper.expiresAt) {
        await AsyncStorage.removeItem(key);
        return null;
      }
      return {
        data: wrapper.data,
        timestamp: wrapper.timestamp,
        expiresAt: wrapper.expiresAt,
        ageMs: Date.now() - wrapper.timestamp,
      };
    } catch {
      await AsyncStorage.removeItem(key);
      return null;
    }
  }

  static async clearAllCachedItems() {
    const nonSensitiveKeys = [
      KEYS.APP_SETTINGS,
      KEYS.USER_PROFILE_PUBLIC,
      KEYS.UI_PREFERENCES,
      KEYS.OFFLINE_CONTENT,
      KEYS.CACHE_METADATA,
      KEYS.SESSION_UI_STATE,
      KEYS.ONBOARDING_COMPLETED,
      KEYS.LAST_SYNC_TIMESTAMP,
      KEYS.CACHED_FEED,
      KEYS.NOTIFICATION_PREFERENCES,
    ];
    await AsyncStorage.multiRemove(nonSensitiveKeys);
  }
}

