class AuthTokenManager {
  /**
   * Store authentication tokens ONLY in secure platform storage.
   *
   * SECURE: Uses SecureStore backed by iOS Keychain / Android Keystore.
   * INSECURE (NEVER DO): AsyncStorage.setItem('token', authToken)
   */
  static async storeTokens({ accessToken, refreshToken, expiresIn }) {
    if (!accessToken) {
      throw new Error('Access token is required');
    }

    await Promise.all([
      SecureStorageManager.setSecureItem(KEYS.SECURE_AUTH_TOKEN, accessToken),
      refreshToken
        ? SecureStorageManager.setSecureItem(KEYS.SECURE_REFRESH_TOKEN, refreshToken)
        : Promise.resolve(),
    ]);

    // Store only the non-sensitive expiration metadata in AsyncStorage
    if (expiresIn) {
      await CacheStorageManager.setItem('@token_expiry_metadata', {
        expiresAt: Date.now() + expiresIn * 1000,
        issuedAt: Date.now(),
      });
    }
  }

  static async getAccessToken() {
    // Check expiration metadata first (fast, non-sensitive check)
    const expiryMeta = await CacheStorageManager.getItem('@token_expiry_metadata');
    if (expiryMeta && expiryMeta.expiresAt && Date.now() > expiryMeta.expiresAt) {
      return { token: null, expired: true };
    }

    const token = await SecureStorageManager.getSecureItem(KEYS.SECURE_AUTH_TOKEN);
    return { token, expired: false };
  }

  static async getRefreshToken() {
    return SecureStorageManager.getSecureItem(KEYS.SECURE_REFRESH_TOKEN);
  }

  /**
   * Validate that the user is truly authenticated by checking
   * for a real token in secure storage.
   *
   * SECURE: Validates actual credential presence.
   * INSECURE (NEVER DO): Checking a raw boolean flag like `isAuthenticated: true`
   *   stored in AsyncStorage that could be tampered with.
   */
  static async isAuthenticated() {
    const { token, expired } = await this.getAccessToken();

    if (expired) {
      // Attempt refresh
      const refreshToken = await this.getRefreshToken();
      return { authenticated: false, canRefresh: !!refreshToken };
    }

    // Authentication is determined by the presence of a real token
    // in secure storage, NOT by a persisted boolean flag.
    return { authenticated: !!token, canRefresh: false };
  }

  static async clearTokens() {
    await Promise.all([
      SecureStorageManager.removeSecureItem(KEYS.SECURE_AUTH_TOKEN),
      SecureStorageManager.removeSecureItem(KEYS.SECURE_REFRESH_TOKEN),
      CacheStorageManager.removeItem('@token_expiry_metadata'),
    ]);
  }
}

