class SessionManager {
  /**
   * Initialize a session. Sensitive session ID goes to secure storage;
   * non-sensitive UI state goes to AsyncStorage.
   */
  static async startSession({ sessionId, userId, displayName, avatarUrl }) {
    // Sensitive: session ID and user ID in secure storage
    await Promise.all([
      SecureStorageManager.setSecureItem(KEYS.SECURE_SESSION_ID, sessionId),
      SecureStorageManager.setSecureItem(KEYS.SECURE_USER_ID, userId),
    ]);

    // Non-sensitive: UI display data in AsyncStorage for fast rendering
    await CacheStorageManager.setItem(KEYS.SESSION_UI_STATE, {
      displayName: displayName || 'User',
      avatarUrl: avatarUrl || null,
      sessionStartedAt: Date.now(),
      lastActiveAt: Date.now(),
    });
  }

  static async getSessionUIState() {
    return CacheStorageManager.getItem(KEYS.SESSION_UI_STATE);
  }

  static async updateLastActive() {
    const state = await CacheStorageManager.getItem(KEYS.SESSION_UI_STATE);
    if (state) {
      state.lastActiveAt = Date.now();
      await CacheStorageManager.setItem(KEYS.SESSION_UI_STATE, state);
    }
  }

  static async getSecureSessionId() {
    return SecureStorageManager.getSecureItem(KEYS.SECURE_SESSION_ID);
  }

  static async getSecureUserId() {
    return SecureStorageManager.getSecureItem(KEYS.SECURE_USER_ID);
  }

  static async endSession() {
    await Promise.all([
      SecureStorageManager.removeSecureItem(KEYS.SECURE_SESSION_ID),
      SecureStorageManager.removeSecureItem(KEYS.SECURE_USER_ID),
      CacheStorageManager.removeItem(KEYS.SESSION_UI_STATE),
    ]);
  }
}

