class OfflineContentManager {
  /**
   * Cache content for offline access. Content is stored with TTL
   * and category-based organization.
   */
  static async cacheContent(contentId, content, category = 'general', ttlMinutes = 1440) {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};

    if (!allContent[category]) {
      allContent[category] = {};
    }

    allContent[category][contentId] = {
      ...content,
      cachedAt: Date.now(),
      expiresAt: Date.now() + ttlMinutes * 60 * 1000,
    };

    await CacheStorageManager.setItem(KEYS.OFFLINE_CONTENT, allContent);
  }

  static async getContent(contentId, category = 'general') {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};
    const categoryContent = allContent[category];

    if (!categoryContent || !categoryContent[contentId]) return null;

    const item = categoryContent[contentId];

    // Check expiration
    if (item.expiresAt && Date.now() > item.expiresAt) {
      delete categoryContent[contentId];
      await CacheStorageManager.setItem(KEYS.OFFLINE_CONTENT, allContent);
      return null;
    }

    return item;
  }

  static async getContentByCategory(category) {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};
    const categoryContent = allContent[category] || {};

    // Filter out expired items
    const now = Date.now();
    const validItems = {};
    let hasExpired = false;

    for (const [id, item] of Object.entries(categoryContent)) {
      if (!item.expiresAt || now <= item.expiresAt) {
        validItems[id] = item;
      } else {
        hasExpired = true;
      }
    }

    // Clean up expired items
    if (hasExpired) {
      allContent[category] = validItems;
      await CacheStorageManager.setItem(KEYS.OFFLINE_CONTENT, allContent);
    }

    return validItems;
  }

  static async removeContent(contentId, category = 'general') {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};
    if (allContent[category]) {
      delete allContent[category][contentId];
      await CacheStorageManager.setItem(KEYS.OFFLINE_CONTENT, allContent);
    }
  }

  static async clearCategory(category) {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};
    delete allContent[category];
    await CacheStorageManager.setItem(KEYS.OFFLINE_CONTENT, allContent);
  }

  static async clearAllOfflineContent() {
    await CacheStorageManager.removeItem(KEYS.OFFLINE_CONTENT);
  }

  static async getOfflineContentStats() {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};
    const stats = { totalItems: 0, categories: {} };

    for (const [category, items] of Object.entries(allContent)) {
      const count = Object.keys(items).length;
      stats.categories[category] = count;
      stats.totalItems += count;
    }

    return stats;
  }

  /**
   * Purge all expired content across all categories.
   */
  static async purgeExpired() {
    const allContent = (await CacheStorageManager.getItem(KEYS.OFFLINE_CONTENT)) || {};
    const now = Date.now();
    let purgedCount = 0;

    for (const category of Object.keys(allContent)) {
      for (const [id, item] of Object.entries(allContent[category])) {
        if (item.expiresAt && now > item.expiresAt) {
          delete allContent[category][id];
          purgedCount++;
        }
      }
      // Remove empty categories
      if (Object.keys(allContent[category]).length === 0) {
        delete allContent[category];
      }
    }

    if (purgedCount > 0) {
      await CacheStorageManager.setItem(KEYS.OFFLINE_CONTENT, allContent);
    }

    return purgedCount;
  }
}

