class CachedFeedManager {
  static async cacheFeed(feedItems, feedType = 'main') {
    const feedData = {
      items: feedItems,
      feedType,
      cachedAt: Date.now(),
    };
    // Cache feed for 15 minutes
    await CacheStorageManager.setItem(`${KEYS.CACHED_FEED}_${feedType}`, feedData, 15);
  }

  static async getFeed(feedType = 'main') {
    return CacheStorageManager.getItem(`${KEYS.CACHED_FEED}_${feedType}`);
  }

  static async getFeedWithFreshness(feedType = 'main') {
    const result = await CacheStorageManager.getItemWithMetadata(
      `${KEYS.CACHED_FEED}_${feedType}`
    );
    if (!result) return { feed: null, isStale: true };

    const STALE_THRESHOLD_MS = 5 * 60 * 1000; // 5 minutes
    return {
      feed: result.data,
      isStale: result.ageMs > STALE_THRESHOLD_MS,
      ageMs: result.ageMs,
    };
  }

  static async clearFeed(feedType = 'main') {
    await CacheStorageManager.removeItem(`${KEYS.CACHED_FEED}_${feedType}`);
  }
}

