class SyncManager {
  static async getLastSyncTimestamp() {
    return CacheStorageManager.getItem(KEYS.LAST_SYNC_TIMESTAMP);
  }

  static async updateLastSyncTimestamp() {
    await CacheStorageManager.setItem(KEYS.LAST_SYNC_TIMESTAMP, {
      timestamp: Date.now(),
      isoString: new Date().toISOString(),
    });
  }

  static async needsSync(maxAgeMinutes = 30) {
    const lastSync = await this.getLastSyncTimestamp();
    if (!lastSync) return true;
    return Date.now() - lastSync.timestamp > maxAgeMinutes * 60 * 1000;
  }
}

