// ============================================================
// MAIN DATA MANAGER (Facade)
// ============================================================

class LocalDataManager {
  // Sub-managers
  static Auth = AuthTokenManager;
  static Session = SessionManager;
  static Profile = UserProfileManager;
  static Settings = AppSettingsManager;
  static UIPreferences = UIPreferencesManager;
  static Notifications = NotificationPreferencesManager;
  static OfflineContent = OfflineContentManager;
  static Feed = CachedFeedManager;
  static Sync = SyncManager;
  static Onboarding = OnboardingManager;

  // Direct access to low-level managers (for advanced use)
  static Secure = SecureStorageManager;
  static Cache = CacheStorageManager;

  /**
   * Full login flow: store tokens securely, cache public profile,
   * and initialize session state.
   */
  static async handleLogin({
    accessToken,
    refreshToken,
    expiresIn,
    userId,
    sessionId,
    displayName,
    avatarUrl,
    bio,
    joinDate,
    preferences,
  }) {
    // 1. Store tokens in SECURE storage (Keychain/Keystore)
    await AuthTokenManager.storeTokens({ accessToken, refreshToken, expiresIn });

    // 2. Start session with secure session ID
    await SessionManager.startSession({
      sessionId,
      userId,
      displayName,
      avatarUrl,
    });

    // 3. Cache public profile in AsyncStorage for fast UI rendering
    await UserProfileManager.cachePublicProfile({
      displayName,
      avatarUrl,
      bio,
      joinDate,
      preferences,
    });

    // 4. Update sync timestamp
    await SyncManager.updateLastSyncTimestamp();
  }

  /**
   * Full logout flow: clear all sensitive data from secure storage
   * and optionally clear cached data.
   */
  static async handleLogout({ clearCache = true } = {}) {
    // 1. ALWAYS clear secure storage first
    await AuthTokenManager.clearTokens();
    await SessionManager.endSession();

    // 2. Clear cached data if requested
    if (clearCache) {
      await UserProfileManager.clearProfile();
      await OfflineContentManager.clearAllOfflineContent();
      await CachedFeedManager.clearFeed();
      await CacheStorageManager.removeItem(KEYS.LAST_SYNC_TIMESTAMP);
    }

    // Note: We intentionally preserve app settings and UI preferences
    // across logouts for better UX.
  }

  /**
   * Complete data wipe - removes everything including settings.
   */
  static async factoryReset() {
    await SecureStorageManager.clearAllSecureItems();
    await CacheStorageManager.clearAllCachedItems();

    // Also clear any dynamically-keyed items
    const allKeys = await AsyncStorage.getAllKeys();
    const appKeys = allKeys.filter((key) => key.startsWith('@'));
    if (appKeys.length > 0) {
      await AsyncStorage.multiRemove(appKeys);
    }
  }

  /**
   * Get a comprehensive status of all stored data.
   * Useful for debugging and settings screens.
   */
  static async getStorageStatus() {
    const [authStatus, sessionUI, profile, settings, uiPrefs, offlineStats, lastSync, onboarded] =
      await Promise.all([
        AuthTokenManager.isAuthenticated(),
        SessionManager.getSessionUIState(),
        UserProfileManager.getProfileWithFreshness(),
        AppSettingsManager.getSettings(),
        UIPreferencesManager.getPreferences(),
        OfflineContentManager.getOfflineContentStats(),
        SyncManager.getLastSyncTimestamp(),
        OnboardingManager.isOnboardingCompleted(),
      ]);

    return {
      authentication: {
        isAuthenticated: authStatus.authenticated,
        canRefresh: authStatus.canRefresh,
      },
      session: {
        hasActiveSession: !!sessionUI,
        displayName: sessionUI?.displayName || null,
        lastActiveAt: sessionUI?.lastActiveAt || null,
      },
      profile: {
        isCached: !!profile.profile,
        isStale: profile.isStale,
        ageMs: profile.ageMs,
      },
      settings: {
        theme: settings.theme,
        language: settings.language,
        offlineModeEnabled: settings.offlineModeEnabled,
      },
      offlineContent: offlineStats,
      sync: {
        lastSyncAt: lastSync?.isoString || null,
        needsSync: await SyncManager.needsSync(),
      },
      onboarding: {
        completed: onboarded,
      },
    };
  }

  /**
   * Perform maintenance: purge expired content, update metadata.
   * Call this periodically (e.g., on app foreground).
   */
  static async performMaintenance() {
    const purgedCount = await OfflineContentManager.purgeExpired();
    await SessionManager.updateLastActive();

    return {
      purgedExpiredItems: purgedCount,
      maintenanceTimestamp: Date.now(),
    };
  }
}

